{
  "version": "1.0",
  "run": {
    "logJson": true,
    "logPath": ".sequant/logs",
    "autoDetectPhases": true,
    "timeout": 1800,
    "sequential": false,
    "qualityLoop": false,
    "maxIterations": 3,
    "smartTests": true,
    "rotation": {
      "enabled": true,
      "maxSizeMB": 10,
      "maxFiles": 100
    },
    "mcp": true,
    "retry": true,
    "staleBranchThreshold": 5,
    "pmRun": "npm run",
    "devUrl": "http://localhost:3000"
  },
  "agents": {
    "parallel": false,
    "model": "haiku"
  },
  "scopeAssessment": {
    "enabled": true,
    "skipIfSimple": true,
    "trivialThresholds": {
      "maxACItems": 3,
      "maxDirectories": 1
    },
