      "featureCount": {
        "yellow": 2,
        "red": 3
      },
      "acItems": {
        "yellow": 6,
        "red": 9
      },
      "fileEstimate": {
        "yellow": 8,
        "red": 13
      },
      "directorySpread": {
        "yellow": 3,
        "red": 5
      }
    }
  }
}
